    _parseColor: function(color) {
        const names = { 'white': '#ffffff', 'black': '#000000', 'red': '#ff0000', 'orange': '#ff9500' };
        if (names[color.toLowerCase()]) color = names[color.toLowerCase()];
        if (color.startsWith('#')) {
            let c = color.substring(1);
            if (c.length === 3) c = c[0] + c[0] + c[1] + c[1] + c[2] + c[2];
            return [parseInt(c.substring(0, 2), 16), parseInt(c.substring(2, 4), 16), parseInt(c.substring(4, 6), 16)];
        }
        let m = color.match(/\d+/g);
        if (m && m.length >= 3) return [parseInt(m[0]), parseInt(m[1]), parseInt(m[2])];
        return [0, 0, 0];
    },

    on_setting_changed: function() {
