            "ayodhya": [26.7922, 82.1998],
            "puri": [19.8135, 85.8312]
        };

        if (this.city && this.city !== "custom" && CITIES[this.city]) {
            this.mylat = CITIES[this.city][0];
            this.mylong = CITIES[this.city][1];
            // Update the spinbuttons in UI if possible (optional in mock, but good for real Cinnamon)
            this.settings.setValue("mylat", this.mylat);
            this.settings.setValue("mylong", this.mylong);
        }

        this.latitude = this.mylat;
        this.longitude = -(this.mylong);
        this.font_size_normal = 12*this.scale_size;
        this.font_size_h2 = (16/12)*12*this.scale_size;
        this.font_size_h1 = (36/12)*12*this.scale_size;

        // Force the outer frame to be transparent so our custom background and opacity work
