        }

        const rgb = this._parseColor(this.background_color);
        const bgColor = `rgba(${rgb[0]}, ${rgb[1]}, ${rgb[2]}, ${this.background_opacity / 100})`;

        this._mainContainer.style = "background-color: "+bgColor+" !important; border: 1px solid "+this.border_color+" !important; border-radius: 10px; padding: 10px;"

