        const timeStyle = "; font-variant-numeric: tabular-nums; font-family: 'Roboto Mono', monospace;";
        const containerMinWidth = " min-width: " + (200 * this.scale_size) + "px;";

        this._calenderContainer.style = containerMinWidth;
        this._panchangContainer.style = containerMinWidth + " margin-left: 10px;";

