        this._sunrise_label.style = "font-size: "+this.font_size_normal+"px; color: "+this.sunrise_color+";" + timeStyle;
        this._sunset_label.style =  "font-size: "+this.font_size_normal+"px; color: "+this.sunset_color+";" + timeStyle;
        this.sunrise_nakshtra_label.style =  "font-size: "+this.font_size_normal+"px; color: "+this.nakshatra_color+";" + timeStyle;
        this.sunrise_tithi_label.style =  "font-size: "+this.font_size_normal+"px; color: "+this.tithi_color+";" + timeStyle;
        this._ayanamsa_label.style =  "font-size: "+this.font_size_normal+"px; color: "+this.text_color+";";

        this._nakshtra.style =  "font-size: "+this.font_size_normal+"px; color: "+this.nakshatra_color+";" + timeStyle;
        this._tithi.style =  "font-size: "+this.font_size_normal+"px; color: "+this.tithi_color+";" + timeStyle;
        this._vaaram.style = "font-size: "+this.font_size_normal+"px; color: "+this.text_color+";";
