    fTs: function(d) { return this.fT(d) + ":" + ("" + d.getSeconds() / 100 + "0000").substr(2, 2); },

    DtJ: function(date_time) {
        var d = new Date();
        d.setTime(date_time);
        d.setMonth(0);
        d.setDate(1);
        var n = date_time / day - d.getTime() / day + 1
        return n;
